          defaultValue={initialValue.current}
          disabled={disabled}
          format={format}
          inputRef={setInputElement}
          onChange={(next) => {
            if (next !== null) publish(next);
          }}
          readOnly={readOnly}
          showContrast={showContrast}
          showPreview={showPreview}
          value={selectedValue}
        />
      </div>
    );
  },
