    border-inline-end: 0;
    border-radius: var(--mrg-component-field-radius) 0 0 var(--mrg-component-field-radius);
    padding-inline: var(--mrg-semantic-space-inline-md);
    color: var(--mrg-component-field-foreground);
    background: var(--mrg-component-field-background);
    font: inherit;
  }

  [dir="rtl"] .mrg-combobox__input {
    border-inline-start: 0;
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-component-field-border);
    border-radius: 0 var(--mrg-component-field-radius) var(--mrg-component-field-radius) 0;
  }

  .mrg-combobox__input::placeholder {
    color: var(--mrg-component-field-placeholder);
  }

  .mrg-combobox__input[data-invalid] {
    border-color: var(--mrg-component-field-border-invalid);
  }

  .mrg-combobox__input[data-focus-visible],
  .mrg-combobox__trigger[data-focus-visible],
  .mrg-combobox__clear:focus-visible,
  .mrg-combobox__item[data-focus-visible] {
    box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
      var(--mrg-component-focus-indicator-contrast-background);
    z-index: 1;
    outline: var(--mrg-component-focus-indicator-width) solid
      var(--mrg-component-focus-indicator-color);
    outline-offset: var(--mrg-component-focus-indicator-offset);
  }

  .mrg-combobox__trigger {
    display: inline-grid;
    place-items: center;
    min-block-size: var(--mrg-semantic-size-target-preferred);
    min-inline-size: var(--mrg-semantic-size-target-preferred);
    block-size: var(--mrg-component-field-height);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-component-field-border);
    border-radius: 0 var(--mrg-component-field-radius) var(--mrg-component-field-radius) 0;
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-surface);
    font: inherit;
    cursor: pointer;
    grid-column: -2 / -1;
    transition:
      background-color var(--mrg-semantic-motion-duration-transition)
        var(--mrg-semantic-motion-easing-standard),
      border-color var(--mrg-semantic-motion-duration-transition)
        var(--mrg-semantic-motion-easing-standard);
  }

  .mrg-combobox__clear {
