    background: var(--mrg-component-control-background);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-component-field-border);
    border-inline-end: 0;
    color: var(--mrg-semantic-color-brand-action);
    cursor: pointer;
    font: inherit;
    font-weight: var(--mrg-semantic-font-weight-label);
    grid-column: 2;
    min-block-size: var(--mrg-semantic-size-target-preferred);
    min-inline-size: var(--mrg-semantic-size-target-preferred);
  }

  .mrg-combobox__clear:not(:disabled):hover {
