    opacity: 1;
  }

  .mrg-combobox__description,
  .mrg-combobox__error {
    margin-block-start: var(--mrg-semantic-space-inline-xs);
    font-size: var(--mrg-semantic-font-size-label);
    line-height: var(--mrg-semantic-font-line-height-body);
  }

  .mrg-combobox__description {
    color: var(--mrg-semantic-color-foreground-muted);
  }

  .mrg-combobox__error {
    color: var(--mrg-semantic-color-status-danger-foreground);
  }

  .mrg-combobox__popover {
    inline-size: var(--trigger-width);
    max-block-size: min(var(--available-height), 20rem);
    overflow: auto;
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-component-overlay-border);
    border-radius: var(--mrg-component-overlay-radius);
    color: var(--mrg-component-overlay-foreground);
    background: var(--mrg-component-overlay-background);
    box-shadow: var(--mrg-component-overlay-elevation);
    transform-origin: var(--trigger-anchor-point);
  }

  .mrg-combobox__popover[data-entering] {
    animation: mrg-combobox-enter var(--mrg-primitive-duration-normal)
      var(--mrg-primitive-easing-enter);
  }

  .mrg-combobox__popover[data-exiting] {
    animation: mrg-combobox-exit var(--mrg-primitive-duration-fast) var(--mrg-primitive-easing-exit);
  }

  .mrg-combobox__listbox {
    display: grid;
    gap: var(--mrg-semantic-border-width-strong);
    padding: var(--mrg-semantic-space-inline-xs);
    outline: none;
  }

  .mrg-combobox__item {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: center;
    min-block-size: var(--mrg-semantic-size-target-preferred);
    border-radius: var(--mrg-component-control-radius);
    padding: var(--mrg-semantic-space-inline-sm) var(--mrg-semantic-space-inline-md);
    cursor: default;
  }

  .mrg-combobox__item[data-focused],
  .mrg-combobox__item[data-hovered] {
    color: var(--mrg-semantic-color-selection-foreground);
    background: var(--mrg-semantic-color-selection-background);
  }

  .mrg-combobox__item[data-disabled] {
    color: var(--mrg-semantic-color-foreground-disabled);
  }

  .mrg-combobox__check {
    visibility: hidden;
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-combobox__item[data-selected] .mrg-combobox__check {
    visibility: visible;
  }

  .mrg-combobox__section-header {
    padding: var(--mrg-semantic-space-inline-sm) var(--mrg-semantic-space-inline-md)
      var(--mrg-semantic-space-inline-xs);
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
    letter-spacing: var(--mrg-semantic-font-letter-spacing-body);
    text-transform: uppercase;
  }

  .mrg-combobox__empty {
    padding: var(--mrg-semantic-space-stack-sm) var(--mrg-semantic-space-inline-md);
    color: var(--mrg-semantic-color-foreground-muted);
  }

  :where([data-density="touch"]) .mrg-combobox__input,
  :where([data-density="touch"]) .mrg-combobox__trigger,
  :where([data-density="touch"]) .mrg-combobox__clear,
  :where([data-density="touch"]) .mrg-combobox__item {
    min-block-size: var(--mrg-semantic-size-target-preferred);
  }

  @keyframes mrg-combobox-enter {
    from {
      opacity: 0;
      transform: translateY(-0.25rem) scale(0.985);
    }
  }

  @keyframes mrg-combobox-exit {
    to {
      opacity: 0;
      transform: translateY(-0.125rem) scale(0.99);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-combobox__trigger {
      transition: none;
    }

    .mrg-combobox__popover[data-entering],
    .mrg-combobox__popover[data-exiting] {
      animation: none;
    }
  }

  @media (forced-colors: active) {
    .mrg-combobox__input,
    .mrg-combobox__clear,
    .mrg-combobox__trigger,
    .mrg-combobox__popover {
      border-color: ButtonText;
      color: ButtonText;
      background: Canvas;
      forced-color-adjust: auto;
    }

    .mrg-combobox__input[data-focus-visible],
    .mrg-combobox__trigger[data-focus-visible],
    .mrg-combobox__clear:focus-visible,
    .mrg-combobox__item[data-focus-visible] {
      box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width) Canvas;
      outline-color: Highlight;
    }

    .mrg-combobox__input[data-invalid] {
      border-color: Mark;
    }

    .mrg-combobox__item[data-focused],
    .mrg-combobox__item[data-selected] {
      color: HighlightText;
      background: Highlight;
    }
  }
}

