"use client";

import "./creatable-select.css";

import {
  forwardRef,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
  type InputHTMLAttributes,
  type KeyboardEvent,
  type ReactElement,
} from "react";

export interface CreatableSelectOption {
  /** Stable canonical value submitted when this option is selected. */
  readonly value: string;
  /** Plain visible label used for search and input display. */
  readonly label: string;
  /** Optional supporting copy rendered under the option label. */
  readonly description?: string;
  /** Keeps the option visible while removing it from selection. */
  readonly disabled?: boolean;
}

export interface CreatableSelectProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "children" | "defaultValue" | "name" | "onChange" | "value"
> {
  /** Persistent visible label and accessible name for the combobox input. */
  readonly label: string;
  /** Ordered existing options searched by their visible labels. */
  readonly options: readonly CreatableSelectOption[];
  /** Controlled canonical selected value, or null for no selection. */
  readonly value?: string | null;
  /** Initial canonical selected value for uncontrolled use and form reset. */
  readonly defaultValue?: string | null;
  /** Reports clear, create, and existing-option selection commits. */
  readonly onValueChange?: (value: string | null, reason: "clear" | "create" | "select") => void;
  /** Enables value creation; omitting it removes the create option and creation behavior. */
  readonly onCreate?: (
    value: string,
    context: {
      /** Signal aborted when creation is cancelled, replaced, or unmounted. */
      readonly signal: AbortSignal;
    },
  ) => void | Promise<void>;
  /** Returns localized recovery text for an invalid proposed value, or null to continue. */
  readonly validateCreate?: (value: string) => string | null;
  /** Controlled creation-pending state; omitted lets the component track its own promise. */
  readonly creating?: boolean;
  /** Consumer cancellation hook invoked after the active creation signal is aborted. */
  readonly onCancelCreate?: () => void;
  /** Native form field name used by the hidden canonical-value input. */
  readonly name?: string;
  /** Native form owner id forwarded to the canonical-value input. */
  readonly form?: string;
  /** Optional visible guidance associated with the combobox input. */
  readonly description?: string;
  /** Optional visible validation message rendered as an alert. */
  readonly errorMessage?: string;
  /** Applies invalid styling and aria-invalid to the combobox input. */
  readonly invalid?: boolean;
  /** Localized message shown when search has no existing or creatable result. */
  readonly emptyMessage?: string;
  /** Renders a canonical-value preview; false removes the output and description id. */
  readonly showCanonicalPreview?: boolean;
  /** Formats only the optional preview and never changes the submitted canonical value. */
  readonly formatCanonicalValue?: (value: string) => string;
}

function assertText(value: string, name: string): void {
  if (value.trim().length === 0)
    throw new TypeError(`Mergora CreatableSelect ${name} must not be empty.`);
}

function nextEnabledChoice(
  options: readonly CreatableSelectOption[],
  includesCreate: boolean,
  start: number,
  delta: 1 | -1,
): number {
  const count = options.length + (includesCreate ? 1 : 0);
  if (count === 0) return -1;
  const origin = start < 0 && delta === -1 ? 0 : start;
  for (let offset = 1; offset <= count; offset += 1) {
    const candidate = (origin + offset * delta + count) % count;
    if (candidate === options.length || options[candidate]?.disabled !== true) return candidate;
  }
  return -1;
}

export const CreatableSelect = forwardRef<HTMLInputElement, CreatableSelectProps>(
  function CreatableSelect(
    {
      className,
      defaultValue = null,
      description,
      disabled = false,
      emptyMessage = "No matching options. Create this value instead.",
      errorMessage,
      form,
      formatCanonicalValue,
      id,
      invalid = false,
      label,
      name,
      onCancelCreate,
      onCreate,
      onKeyDown,
      onValueChange,
      options,
      placeholder = "Choose or create a value",
      readOnly = false,
      required = false,
      showCanonicalPreview = false,
      creating,
      validateCreate,
      value,
      ...inputProps
    },
    forwardedRef,
  ): ReactElement {
    assertText(label, "label");
    assertText(emptyMessage, "empty message");
    if (name !== undefined) assertText(name, "name");
    const values = new Set<string>();
    for (const option of options) {
      assertText(option.value, "option value");
      assertText(option.label, "option label");
      if (values.has(option.value))
        throw new TypeError(`Mergora CreatableSelect value ${option.value} is duplicated.`);
      values.add(option.value);
    }
    const generatedId = `mrg-creatable-select-${useId().replaceAll(":", "")}`;
    const inputId = id ?? generatedId;
    const listboxId = `${inputId}-listbox`;
    const descriptionId = description === undefined ? undefined : `${inputId}-description`;
    const errorId = errorMessage === undefined ? undefined : `${inputId}-error`;
    const previewId = `${inputId}-canonical-preview`;
    const controlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<string | null>(defaultValue);
    const currentValue = controlled ? value : internalValue;
    const selectedOption = options.find((option) => option.value === currentValue);
    const initialLabel = selectedOption?.label ?? currentValue ?? "";
    const [query, setQuery] = useState(initialLabel);
    const [open, setOpen] = useState(false);
    const [activeIndex, setActiveIndex] = useState(-1);
    const [internalCreating, setInternalCreating] = useState(false);
    const [creationError, setCreationError] = useState<string | null>(null);
    const inputRef = useRef<HTMLInputElement | null>(null);
    const createController = useRef<AbortController | null>(null);
    const createPending = creating ?? internalCreating;
    const normalizedQuery = query.trim().toLocaleLowerCase();
    const matches = useMemo(
      () => options.filter((option) => option.label.toLocaleLowerCase().includes(normalizedQuery)),
      [normalizedQuery, options],
    );
    const exactMatch = options.some(
      (option) => option.label.toLocaleLowerCase() === normalizedQuery,
    );
    const canCreate =
      normalizedQuery.length > 0 && !exactMatch && onCreate !== undefined && !createPending;
    const canonical =
      showCanonicalPreview && query.trim().length > 0
        ? (formatCanonicalValue?.(query.trim()) ?? query.trim())
        : null;

    useEffect(() => {
      if (controlled)
        setQuery(options.find((option) => option.value === value)?.label ?? value ?? "");
    }, [controlled, options, value]);

    useEffect(() => {
      const input = inputRef.current;
      const associatedForm = input?.form;
      if (associatedForm === null || associatedForm === undefined || controlled) return;
      const restore = () => {
        setInternalValue(defaultValue);
        const next =
          options.find((option) => option.value === defaultValue)?.label ?? defaultValue ?? "";
        setQuery(next);
        setOpen(false);
      };
      associatedForm.addEventListener("reset", restore);
      return () => associatedForm.removeEventListener("reset", restore);
    }, [controlled, defaultValue, options]);

    useEffect(() => () => createController.current?.abort(), []);

    const setInputRef = (node: HTMLInputElement | null) => {
      inputRef.current = node;
      if (typeof forwardedRef === "function") forwardedRef(node);
      else if (forwardedRef !== null) forwardedRef.current = node;
    };
    const commit = (next: string | null, reason: "clear" | "create" | "select") => {
      if (!controlled) setInternalValue(next);
      onValueChange?.(next, reason);
    };
    const selectOption = (option: CreatableSelectOption) => {
      if (disabled || readOnly || option.disabled === true) return;
      setQuery(option.label);
      commit(option.value, "select");
      setOpen(false);
      setActiveIndex(-1);
    };
    const finishCreation = (next: string, controller: AbortController) => {
      if (controller.signal.aborted) return;
      commit(next, "create");
      setQuery(next);
      setOpen(false);
      setActiveIndex(-1);
      setCreationError(null);
    };
    const failCreation = (error: unknown, controller: AbortController) => {
      if (controller.signal.aborted) return;
      setCreationError(error instanceof Error ? error.message : "Creation failed. Try again.");
    };
    const create = () => {
      const next = query.trim();
      if (!canCreate || disabled || readOnly || createPending || onCreate === undefined) return;
      const validationMessage = validateCreate?.(next) ?? null;
      if (validationMessage !== null) {
        assertText(validationMessage, "creation validation message");
        setCreationError(validationMessage);
        return;
      }
      const controller = new AbortController();
      createController.current?.abort();
      createController.current = controller;
      if (creating === undefined) setInternalCreating(true);
      setCreationError(null);
      try {
        const result = onCreate(next, { signal: controller.signal });
        void Promise.resolve(result)
          .then(() => finishCreation(next, controller))
          .catch((error: unknown) => failCreation(error, controller))
          .finally(() => {
            if (createController.current === controller) createController.current = null;
            if (creating === undefined) setInternalCreating(false);
          });
      } catch (error) {
        failCreation(error, controller);
        createController.current = null;
        if (creating === undefined) setInternalCreating(false);
      }
    };
    const cancelCreation = () => {
      createController.current?.abort();
      createController.current = null;
      if (creating === undefined) setInternalCreating(false);
      setCreationError("Creation cancelled.");
      onCancelCreate?.();
    };
    const handleKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
      onKeyDown?.(event);
      if (event.defaultPrevented || disabled || readOnly || createPending) return;
      if (event.key === "ArrowDown") {
        event.preventDefault();
        setOpen(true);
        setActiveIndex((index) => nextEnabledChoice(matches, canCreate, index, 1));
      } else if (event.key === "ArrowUp") {
        event.preventDefault();
        setActiveIndex((index) => nextEnabledChoice(matches, canCreate, index, -1));
      } else if (event.key === "Home" && open) {
        event.preventDefault();
        setActiveIndex(nextEnabledChoice(matches, canCreate, -1, 1));
      } else if (event.key === "End" && open) {
        event.preventDefault();
        setActiveIndex(nextEnabledChoice(matches, canCreate, 0, -1));
      } else if (event.key === "Enter" && open && activeIndex >= 0) {
        event.preventDefault();
        const option = matches[activeIndex];
        if (option !== undefined) selectOption(option);
        else create();
      } else if (event.key === "Escape") {
        event.preventDefault();
        setOpen(false);
      }
    };
    const activeId = activeIndex < 0 ? undefined : `${inputId}-choice-${activeIndex}`;
    const describedBy = [descriptionId, errorId, canonical === null ? undefined : previewId]
      .filter(Boolean)
      .join(" ");

    return (
      <div
        className={["mrg-creatable-select", className].filter(Boolean).join(" ")}
        data-disabled={disabled || undefined}
        data-invalid={invalid || undefined}
        data-slot="creatable-select"
      >
        <label htmlFor={inputId}>
          {label}
          {required ? <span aria-hidden="true"> *</span> : null}
        </label>
        {description === undefined ? null : (
          <span className="mrg-creatable-select__description" id={descriptionId}>
            {description}
          </span>
        )}
        <div className="mrg-creatable-select__control">
          <input
            {...inputProps}
            aria-activedescendant={activeId}
            aria-autocomplete="list"
            aria-controls={listboxId}
            aria-describedby={describedBy || undefined}
            aria-expanded={open}
            aria-haspopup="listbox"
            aria-invalid={invalid || undefined}
            aria-busy={createPending || undefined}
            autoComplete="off"
            disabled={disabled}
            form={form}
            id={inputId}
            onBlur={(event) => {
              const control = event.currentTarget.parentElement;
              requestAnimationFrame(() => {
                if (!control?.contains(document.activeElement)) setOpen(false);
              });
            }}
            onChange={(event) => {
              setQuery(event.currentTarget.value);
              if (event.currentTarget.value.length === 0) commit(null, "clear");
              setOpen(true);
              setActiveIndex(-1);
            }}
            onFocus={() => setOpen(true)}
            onKeyDown={handleKeyDown}
            placeholder={placeholder}
            readOnly={readOnly || createPending}
            ref={setInputRef}
            required={required && currentValue === null}
            role="combobox"
            value={query}
          />
          {currentValue === null || readOnly || disabled ? null : (
            <button
              aria-label={`Clear ${label}`}
              onClick={() => {
                setQuery("");
                commit(null, "clear");
                inputRef.current?.focus();
              }}
              type="button"
            >
              ×
            </button>
          )}
        </div>
        {name === undefined || currentValue === null ? null : (
          <input form={form} name={name} type="hidden" value={currentValue} />
        )}
        {open ? (
          <ul id={listboxId} role="listbox">
            {matches.length === 0 && !canCreate ? (
              <li
                aria-disabled="true"
                aria-selected="false"
                className="mrg-creatable-select__empty"
                role="option"
              >
                {emptyMessage}
              </li>
            ) : null}
            {matches.map((option, index) => (
              <li
                aria-disabled={option.disabled || undefined}
                aria-selected={option.value === currentValue}
                data-active={index === activeIndex || undefined}
                data-disabled={option.disabled || undefined}
                id={`${inputId}-choice-${index}`}
                key={option.value}
                onClick={() => selectOption(option)}
                onMouseDown={(event) => event.preventDefault()}
                role="option"
              >
                <span>{option.label}</span>
                {option.description === undefined ? null : <small>{option.description}</small>}
              </li>
            ))}
            {canCreate ? (
              <li
                aria-selected="false"
                data-active={activeIndex === matches.length || undefined}
                id={`${inputId}-choice-${matches.length}`}
                onClick={create}
                onMouseDown={(event) => event.preventDefault()}
                role="option"
              >
                Create “{query.trim()}”
              </li>
            ) : null}
          </ul>
        ) : null}
        {canonical === null ? null : (
          <output
            className="mrg-creatable-select__preview"
            data-slot="creatable-select-canonical-preview"
            id={previewId}
          >
            Canonical value: <strong>{canonical}</strong>
          </output>
        )}
        {createPending ? (
          <div aria-live="polite" className="mrg-creatable-select__lifecycle" role="status">
            <span>Creating {query.trim()}...</span>
            <button onClick={cancelCreation} type="button">
              Cancel creation
            </button>
          </div>
        ) : null}
        {creationError === null ? null : (
          <span className="mrg-creatable-select__creation-error" role="alert">
            {creationError}
          </span>
        )}
        {errorMessage === undefined ? null : (
          <span className="mrg-creatable-select__error" id={errorId} role="alert">
            {errorMessage}
          </span>
        )}
      </div>
    );
  },
);

export type CrudDataRecordStatus = "active" | "archived" | "draft";

export interface CrudDataRecord {
  /** Human-readable category used for filtering and editing. */
  readonly category: string;
  /** Stable unique record identifier used for selection and mutations. */
  readonly id: string;
  /** Required human-readable record name. */
  readonly name: string;
  /** Record lifecycle used for filtering, bulk updates, and status treatment. */
  readonly status: CrudDataRecordStatus;
  /** ISO-compatible mutation instant used for localized display and sorting. */
  readonly updatedAt: string;
}

export interface CrudDataRecordInput {
  /** Required human-readable category for a created or updated record. */
  readonly category: string;
  /** Required human-readable name for a created or updated record. */
  readonly name: string;
  /** Desired lifecycle for a created or updated record. */
  readonly status: CrudDataRecordStatus;
}

export interface CrudDataPermissions {
  /** Whether bulk mutation controls may be exposed and executed. */
  readonly canBulkUpdate: boolean;
  /** Whether record creation controls may be exposed and executed. */
  readonly canCreate: boolean;
  /** Whether destructive record actions may be exposed and executed. */
  readonly canDelete: boolean;
  /** Whether record editing controls may be exposed and executed. */
  readonly canUpdate: boolean;
}

export interface CrudDataSavedView {
  /** Optional category filter restored by this saved view. */
  readonly category?: string;
  /** Stable unique view identifier used for selection and replacement. */
  readonly id: string;
  /** Human-readable saved-view label. */
  readonly label: string;
  /** Optional search query restored by this saved view. */
  readonly search?: string;
}

export interface CrudDataWorkspaceSnapshot {
  /** Authorization snapshot controlling which mutation surfaces are available. */
  readonly permissions: CrudDataPermissions;
  /** Immutable records available to the workspace table. */
  readonly records: readonly CrudDataRecord[];
  /** Immutable consumer-owned saved query and category views. */
  readonly savedViews: readonly CrudDataSavedView[];
}

export interface CrudDataWorkspaceAdapter {
  /** Optionally applies a patch to many records; omission cleanly removes bulk mutation behavior. */
  readonly bulkUpdate?: (
    recordIds: readonly string[],
    patch: Partial<CrudDataRecordInput>,
    signal: AbortSignal,
  ) => Promise<readonly CrudDataRecord[]>;
  /** Creates a record and returns its canonical server-owned representation. */
  readonly create: (input: CrudDataRecordInput, signal: AbortSignal) => Promise<CrudDataRecord>;
  /** Permanently deletes one record through the consumer service. */
  readonly delete: (recordId: string, signal: AbortSignal) => Promise<void>;
  /** Loads the current immutable records, permissions, and saved views. */
  readonly load: (signal: AbortSignal) => Promise<CrudDataWorkspaceSnapshot>;
  /** Optionally restores a deleted record; omission cleanly removes undo behavior. */
  readonly restore?: (record: CrudDataRecord, signal: AbortSignal) => Promise<CrudDataRecord>;
  /** Optionally persists a saved view; omission cleanly removes saved-view authoring. */
  readonly saveView?: (view: CrudDataSavedView, signal: AbortSignal) => Promise<void>;
  /** Updates one record and returns its canonical server-owned representation. */
  readonly update: (
    recordId: string,
    input: CrudDataRecordInput,
    signal: AbortSignal,
  ) => Promise<CrudDataRecord>;
}

const FIXTURE_TIMES = {
  current: "1970-01-01T00:00:00.000Z",
  older: "1969-12-30T01:45:00.000Z",
  prior: "1969-12-31T05:30:00.000Z",
} as const;

function abortIfNeeded(signal: AbortSignal): void {
  if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
}

export function createDeterministicCrudDataWorkspaceAdapter(): CrudDataWorkspaceAdapter {
  let records: CrudDataRecord[] = [
    {
      category: "Documentation",
      id: "record-guidance",
      name: "Keyboard guidance",
      status: "active",
      updatedAt: FIXTURE_TIMES.current,
    },
    {
      category: "Component",
      id: "record-selector",
      name: "Locale selector",
      status: "draft",
      updatedAt: FIXTURE_TIMES.prior,
    },
    {
      category: "Evidence",
      id: "record-touch",
      name: "Touch interaction record",
      status: "active",
      updatedAt: FIXTURE_TIMES.older,
    },
  ];
  let sequence = records.length;
  return {
    async bulkUpdate(recordIds, patch, signal) {
      abortIfNeeded(signal);
      const ids = new Set(recordIds);
      records = records.map((record) =>
        ids.has(record.id) ? { ...record, ...patch, updatedAt: FIXTURE_TIMES.current } : record,
      );
      return records.filter((record) => ids.has(record.id));
    },
    async create(input, signal) {
      abortIfNeeded(signal);
      sequence += 1;
      const record: CrudDataRecord = {
        ...input,
        id: `record-${sequence}`,
        updatedAt: FIXTURE_TIMES.current,
      };
      records = [...records, record];
      return record;
    },
    async delete(recordId, signal) {
      abortIfNeeded(signal);
      records = records.filter((record) => record.id !== recordId);
    },
    async load(signal) {
      abortIfNeeded(signal);
      return {
        permissions: {
          canBulkUpdate: true,
          canCreate: true,
          canDelete: true,
          canUpdate: true,
        },
        records,
        savedViews: [
          { id: "view-active", label: "Active records", search: "active" },
          { category: "Evidence", id: "view-evidence", label: "Evidence only" },
        ],
      };
    },
    async restore(record, signal) {
      abortIfNeeded(signal);
      records = [...records.filter((item) => item.id !== record.id), record];
      return record;
    },
    async saveView(_view, signal) {
      abortIfNeeded(signal);
    },
    async update(recordId, input, signal) {
      abortIfNeeded(signal);
      const updated: CrudDataRecord = {
        ...input,
        id: recordId,
        updatedAt: FIXTURE_TIMES.current,
      };
      records = records.map((record) => (record.id === recordId ? updated : record));
      return updated;
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import type {
  CrudDataRecord,
  CrudDataRecordInput,
  CrudDataWorkspaceAdapter,
  CrudDataWorkspaceSnapshot,
} from "./crud-data-workspace-adapter";

export type CrudDataWorkspaceLoadState = "empty" | "error" | "loading" | "offline" | "ready";
export type CrudDataMutationState = "error" | "idle" | "pending" | "success";

export interface UseCrudDataWorkspaceOptions {
  /** Consumer adapter that owns records, authorization, persistence, and recovery. */
  readonly adapter: CrudDataWorkspaceAdapter;
  /** Prevents adapter requests and exposes explicit offline recovery state. */
  readonly offline?: boolean;
  /** Applies reversible local previews before mutation completion when enabled. */
  readonly optimisticMutations?: boolean;
}

export function useCrudDataWorkspace({
  adapter,
  offline = false,
  optimisticMutations = false,
}: UseCrudDataWorkspaceOptions) {
  const [snapshot, setSnapshot] = useState<CrudDataWorkspaceSnapshot | null>(null);
  const [state, setState] = useState<CrudDataWorkspaceLoadState>(offline ? "offline" : "loading");
  const [mutationState, setMutationState] = useState<CrudDataMutationState>("idle");
  const [error, setError] = useState("");
  const [lastDeleted, setLastDeleted] = useState<CrudDataRecord | null>(null);
  const [lastOperation, setLastOperation] = useState("");
  const activeRequest = useRef<AbortController | null>(null);
  const optimisticSequence = useRef(0);

  const reload = useCallback(async () => {
    activeRequest.current?.abort();
    if (offline) {
      setState("offline");
      return;
    }
    const controller = new AbortController();
    activeRequest.current = controller;
    setState("loading");
    setError("");
    try {
      const next = await adapter.load(controller.signal);
      if (controller.signal.aborted) return;
      setSnapshot(next);
      setState(next.records.length === 0 ? "empty" : "ready");
    } catch (loadError) {
      if (controller.signal.aborted) return;
      setError(loadError instanceof Error ? loadError.message : "Records could not be loaded.");
      setState("error");
    } finally {
      if (activeRequest.current === controller) activeRequest.current = null;
    }
  }, [adapter, offline]);

  useEffect(() => {
    void reload();
    return () => activeRequest.current?.abort();
  }, [reload]);

  const startMutation = () => {
    activeRequest.current?.abort();
    const controller = new AbortController();
    activeRequest.current = controller;
    setMutationState("pending");
    setError("");
    return controller;
  };

  const failMutation = (controller: AbortController, mutationError: unknown) => {
    if (controller.signal.aborted) return;
    setError(
      mutationError instanceof Error ? mutationError.message : "The change could not be saved.",
    );
    setMutationState("error");
    if (activeRequest.current === controller) activeRequest.current = null;
  };

  const finishMutation = (controller: AbortController, message: string) => {
    if (controller.signal.aborted) return;
    setMutationState("success");
    setLastOperation(message);
    setState("ready");
    if (activeRequest.current === controller) activeRequest.current = null;
  };

  const createRecord = async (input: CrudDataRecordInput) => {
    if (snapshot === null || offline || !snapshot.permissions.canCreate) return;
    const controller = startMutation();
    optimisticSequence.current += 1;
    const temporary: CrudDataRecord = {
      ...input,
      id: `optimistic-${optimisticSequence.current}`,
      updatedAt: new Date().toISOString(),
    };
    const previous = snapshot;
    if (optimisticMutations) {
      setSnapshot({ ...snapshot, records: [...snapshot.records, temporary] });
    }
    try {
      const created = await adapter.create(input, controller.signal);
      setSnapshot((current) => {
        if (current === null) return current;
        return {
          ...current,
          records: optimisticMutations
            ? current.records.map((record) => (record.id === temporary.id ? created : record))
            : [...current.records, created],
        };
      });
      finishMutation(controller, `Created ${created.name}.`);
    } catch (createError) {
      if (optimisticMutations) setSnapshot(previous);
      failMutation(controller, createError);
    }
  };

  const updateRecord = async (recordId: string, input: CrudDataRecordInput) => {
    if (snapshot === null || offline || !snapshot.permissions.canUpdate) return;
    const controller = startMutation();
    const previous = snapshot;
    if (optimisticMutations) {
      setSnapshot({
        ...snapshot,
        records: snapshot.records.map((record) =>
          record.id === recordId
            ? { ...record, ...input, updatedAt: new Date().toISOString() }
            : record,
        ),
      });
    }
    try {
      const updated = await adapter.update(recordId, input, controller.signal);
      setSnapshot((current) =>
        current === null
          ? current
          : {
              ...current,
              records: current.records.map((record) => (record.id === recordId ? updated : record)),
            },
      );
      finishMutation(controller, `Updated ${updated.name}.`);
    } catch (updateError) {
      if (optimisticMutations) setSnapshot(previous);
      failMutation(controller, updateError);
    }
  };

  const deleteRecord = async (recordId: string) => {
    if (snapshot === null || offline || !snapshot.permissions.canDelete) return;
    const record = snapshot.records.find((item) => item.id === recordId);
    if (record === undefined) return;
    const controller = startMutation();
    const previous = snapshot;
    if (optimisticMutations) {
      setSnapshot({
        ...snapshot,
        records: snapshot.records.filter((item) => item.id !== recordId),
      });
    }
    try {
      await adapter.delete(recordId, controller.signal);
      if (!optimisticMutations) {
        setSnapshot((current) =>
          current === null
            ? current
            : { ...current, records: current.records.filter((item) => item.id !== recordId) },
        );
      }
      setLastDeleted(record);
      finishMutation(controller, `Deleted ${record.name}.`);
    } catch (deleteError) {
      if (optimisticMutations) setSnapshot(previous);
      failMutation(controller, deleteError);
    }
  };

  const restoreDeleted = async () => {
    if (snapshot === null || lastDeleted === null || adapter.restore === undefined || offline)
      return;
    const controller = startMutation();
    try {
      const restored = await adapter.restore(lastDeleted, controller.signal);
      setSnapshot((current) =>
        current === null
          ? current
          : {
              ...current,
              records: [...current.records.filter((record) => record.id !== restored.id), restored],
            },
      );
      setLastDeleted(null);
      finishMutation(controller, `Restored ${restored.name}.`);
    } catch (restoreError) {
      failMutation(controller, restoreError);
    }
  };

  const bulkSetStatus = async (
    recordIds: readonly string[],
    status: CrudDataRecordInput["status"],
  ) => {
    if (
      snapshot === null ||
      recordIds.length === 0 ||
      adapter.bulkUpdate === undefined ||
      !snapshot.permissions.canBulkUpdate ||
      offline
    ) {
      return;
    }
    const controller = startMutation();
    const previous = snapshot;
    if (optimisticMutations) {
      const ids = new Set(recordIds);
      setSnapshot({
        ...snapshot,
        records: snapshot.records.map((record) =>
          ids.has(record.id) ? { ...record, status } : record,
        ),
      });
    }
    try {
      const updated = await adapter.bulkUpdate(recordIds, { status }, controller.signal);
      const updates = new Map(updated.map((record) => [record.id, record]));
      setSnapshot((current) =>
        current === null
          ? current
          : {
              ...current,
              records: current.records.map((record) => updates.get(record.id) ?? record),
            },
      );
      finishMutation(controller, `Updated ${updated.length} records.`);
    } catch (bulkError) {
      if (optimisticMutations) setSnapshot(previous);
      failMutation(controller, bulkError);
    }
  };

  const saveView = async (label: string, search: string, category: string) => {
    if (snapshot === null || adapter.saveView === undefined || offline || label.trim() === "")
      return;
    const controller = startMutation();
    const id = `view-${
      label
        .trim()
        .toLocaleLowerCase()
        .replace(/[^\p{L}\p{N}]+/gu, "-")
        .replace(/^-|-$/gu, "") || "custom"
    }`;
    const view = {
      ...(category === "all" ? {} : { category }),
      id,
      label: label.trim(),
      ...(search.trim() === "" ? {} : { search: search.trim() }),
    };
    try {
      await adapter.saveView(view, controller.signal);
      setSnapshot((current) =>
        current === null
          ? current
          : {
              ...current,
              savedViews: [...current.savedViews.filter((item) => item.id !== id), view],
            },
      );
      finishMutation(controller, `Saved view ${view.label}.`);
    } catch (saveError) {
      failMutation(controller, saveError);
    }
  };

  const cancelMutation = () => {
    activeRequest.current?.abort();
    activeRequest.current = null;
    setMutationState("idle");
    setLastOperation("Change cancelled.");
  };

  const clearError = () => {
    setError("");
    setMutationState("idle");
  };

  return {
    bulkSetStatus,
    cancelMutation,
    clearError,
    createRecord,
    deleteRecord,
    error,
    lastDeleted,
    lastOperation,
    mutationState,
    reload,
    restoreDeleted,
    saveView,
    snapshot,
    state,
    updateRecord,
  } as const;
}

