  const { isOpen, kind, markReason } = useDialogContext("Close");
  const messageKey =
    kind === "alert-dialog"
      ? "alertDialog.cancel"
      : kind === "sheet"
        ? "sheet.close"
        : "dialog.close";
  const fallback =
    kind === "alert-dialog" ? "Cancel" : kind === "sheet" ? "Close panel" : "Close dialog";
