DrawerFooter.displayName = "Drawer.Footer";

export type DrawerTitleProps = ComponentPropsWithoutRef<typeof SheetTitle>;
export const DrawerTitle = forwardRef<HTMLHeadingElement, DrawerTitleProps>(
