DrawerClose.displayName = "Drawer.Close";
markDialogPart(DrawerClose, "close");

export const Drawer = Object.freeze({
  Close: DrawerClose,
  Content: DrawerContent,
  Description: DrawerDescription,
  Footer: DrawerFooter,
  Header: DrawerHeader,
  Overlay: DrawerOverlay,
  Root: DrawerRoot,
  Title: DrawerTitle,
  Trigger: DrawerTrigger,
});

