"use client";

import {
  forwardRef,
  useEffect,
  useId,
  useRef,
  useState,
  type HTMLAttributes,
  type ReactNode,
} from "react";

import {
  Dropzone,
  type FileRejectionReason,
  type FileSelectionResult,
  type RejectedFileSelection,
} from "../dropzone/index";
import { synchronizeFileInputFiles } from "../file-trigger/file-trigger";
import { useMergoraContext } from "../provider/index";
import {
  UploadProgress,
  formatUploadBytes,
  type UploadProgressStatus,
} from "../upload-progress/index";
import "./file-upload.css";

export type FileUploadChangeReason = "remove" | "reorder" | "reset" | "selection";
export type FileUploadDuplicatePolicy = "allow" | "reject";
export type FileUploadRejectionReason = FileRejectionReason | "duplicate";

export interface FileUploadItem {
  /** Browser File retained for native form serialization and consumer-controlled upload work. */
  readonly file: File;
  /** Stable unique queue identifier used for updates, reordering, and action callbacks. */
  readonly id: string;
  /** Optional consumer status detail displayed by the progress enhancement. */
  readonly message?: ReactNode;
  /** Percentage from zero through 100 for progress without byte totals. */
  readonly progress?: number;
  /** Upload lifecycle status rendered only when progress or relevant actions are enabled. */
  readonly status?: UploadProgressStatus;
  /** Total byte count paired with `uploadedBytes` for byte-based progress. */
  readonly totalBytes?: number;
  /** Completed byte count paired with `totalBytes` for byte-based progress. */
  readonly uploadedBytes?: number;
}

export interface FileUploadRejectedFile extends Omit<RejectedFileSelection, "reason"> {
  /** Existing queue item ID that shares the duplicate key, when rejected as a duplicate. */
  readonly duplicateOf?: string;
  /** Machine-readable reason this file did not enter the managed queue. */
  readonly reason: FileUploadRejectionReason;
}

export interface FileUploadSelectionResult {
  /** Newly created immutable queue items accepted during this selection. */
  readonly accepted: readonly FileUploadItem[];
  /** Immutable recovery records for rejected files, including optional duplicate ownership. */
  readonly rejected: readonly FileUploadRejectedFile[];
  /** Picker, paste, or drop path that produced the selection. */
  readonly source: FileSelectionResult["source"];
}

export interface FileUploadChangeDetail {
  /** Queue item affected by remove or reorder changes, when one item owns the change. */
  readonly itemId?: string;
  /** Stable reason describing selection, removal, reordering, or native form reset. */
  readonly reason: FileUploadChangeReason;
  /** Accepted and rejected selection detail supplied for `selection` changes only. */
  readonly selection?: FileUploadSelectionResult;
}

export interface FileUploadMessages {
  /** Builds the accessible cancellation action label for a queue item. */
  readonly cancel: (name: string) => string;
  /** Empty queue copy shown when no managed files remain. */
  readonly empty: string;
  /** Builds the accessible action label for moving an item later in the queue. */
  readonly moveDown: (name: string) => string;
  /** Builds the accessible action label for moving an item earlier in the queue. */
  readonly moveUp: (name: string) => string;
  /** Heading that provides the managed queue's accessible section name. */
  readonly queueLabel: string;
  /** Heading for the optional rejected-file recovery section. */
  readonly rejectedHeading: string;
  /** Builds the accessible removal action label for a queue item. */
  readonly remove: (name: string) => string;
  /** Builds the accessible retry action label for an errored queue item. */
  readonly retry: (name: string) => string;
}

export interface FileUploadProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children" | "defaultValue" | "form" | "onChange" | "onReset"
> {
  /** MIME types, extensions, or wildcards accepted by the picker and shared preflight classifier. */
  readonly acceptedFileTypes?: readonly string[];
  /** Allows multiple files per selection; false limits each input path to one. */
  readonly allowsMultiple?: boolean;
  /** Initial queue for uncontrolled use; omit when providing controlled `items`. */
  readonly defaultItems?: readonly FileUploadItem[];
  /** Optional visible selection guidance linked to the nested drop surface. */
  readonly description?: ReactNode;
  /** Disables selection and all enabled queue actions without removing queue context. */
  readonly disabled?: boolean;
  /** Duplicate handling policy; `reject` runs `getDuplicateKey` before queue insertion. */
  readonly duplicatePolicy?: FileUploadDuplicatePolicy;
  /** ID of an external form that owns the native file input. */
  readonly form?: string;
  /** Produces a deterministic comparison key when duplicate rejection is enabled. */
  readonly getDuplicateKey?: (file: File) => string;
  /** Produces each new queue item's unique ID; duplicate returned IDs throw explicitly. */
  readonly getFileId?: (file: File, sequence: number) => string;
  /** Controlled queue; changes are reported without mutating this collection. */
  readonly items?: readonly FileUploadItem[];
  /** Required visible label naming the nested drop surface. */
  readonly label: ReactNode;
  /** Maximum total queue length enforced across existing and newly selected items. */
  readonly maxFiles?: number;
  /** Maximum accepted byte size when `validateFileSize` is enabled. */
  readonly maxSizeBytes?: number;
  /** Localized queue, recovery, and action copy with safe defaults for omitted entries. */
  readonly messages?: Partial<FileUploadMessages>;
  /** Native form field name used to serialize the current queue's File objects. */
  readonly name?: string;
  /** Invoked for an enabled cancel action; network cancellation remains consumer-owned. */
  readonly onCancel?: (item: FileUploadItem) => void;
  /** Reports immutable controlled or uncontrolled queue changes with a precise reason. */
  readonly onItemsChange?: (
    items: readonly FileUploadItem[],
    detail: FileUploadChangeDetail,
  ) => void;
  /** Invoked for an enabled retry action; upload and retry behavior remain consumer-owned. */
  readonly onRetry?: (item: FileUploadItem) => void;
  /** Runs after native form reset clears the queue and recovery state. */
  readonly onReset?: () => void;
  /** Receives newly accepted and rejected files independently of queue change handling. */
  readonly onSelection?: (result: FileUploadSelectionResult) => void;
  /** Prevents selection and queue mutation while retaining normal readable semantics. */
  readonly readOnly?: boolean;
  /** Renders an optional consumer-owned preview before each queue item's file metadata. */
  readonly renderPreview?: (item: FileUploadItem) => ReactNode;
  /** Adds earlier/later queue controls; false removes their UI and reorder events. */
  readonly reorderable?: boolean;
  /** Adds cancellation actions for active items when `onCancel` is supplied. */
  readonly showCancelActions?: boolean;
  /** Adds per-item progress semantics; false removes progress UI and announcements. */
  readonly showProgress?: boolean;
  /** Adds the live rejected-file recovery section; false retains no rejection UI state. */
  readonly showRejectionRecovery?: boolean;
  /** Adds queue removal controls; false removes their UI and remove events. */
  readonly showRemoveActions?: boolean;
  /** Adds retry actions for errored items when `onRetry` is supplied. */
  readonly showRetryActions?: boolean;
  /** Applies native required validation to the nested file input. */
  readonly required?: boolean;
  /** Enables byte-size preflight validation; false removes only size rejection. */
  readonly validateFileSize?: boolean;
}

const DEFAULT_MESSAGES: FileUploadMessages = {
  cancel: (name) => `Cancel ${name}`,
  empty: "No files in the queue.",
  moveDown: (name) => `Move ${name} later in the queue`,
  moveUp: (name) => `Move ${name} earlier in the queue`,
  queueLabel: "Selected files",
  rejectedHeading: "Files that need attention",
  remove: (name) => `Remove ${name}`,
  retry: (name) => `Retry ${name}`,
};

function hasVisibleContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasVisibleContent);
  return true;
}

function assertMessage(value: string, label: string): string {
  if (value.trim().length === 0 || [...value].length > 512) {
    throw new RangeError(`Mergora FileUpload ${label} must contain 1 through 512 characters.`);
  }
  return value;
}

function assertItem(item: FileUploadItem): void {
  if (!(item.file instanceof File)) throw new TypeError("Mergora FileUpload items require a File.");
  if (item.id.trim().length === 0 || item.id.length > 512) {
    throw new RangeError("Mergora FileUpload item ids must contain 1 through 512 characters.");
  }
}

function assertProgressItem(item: FileUploadItem): void {
  if (
    item.progress !== undefined &&
    (!Number.isFinite(item.progress) || item.progress < 0 || item.progress > 100)
  ) {
    throw new RangeError("Mergora FileUpload item progress must be from zero through 100.");
  }
  if ((item.uploadedBytes === undefined) !== (item.totalBytes === undefined)) {
    throw new RangeError("Mergora FileUpload byte values must be supplied together.");
  }
}

function assertItems(items: readonly FileUploadItem[]): void {
  const ids = new Set<string>();
  for (const item of items) {
    assertItem(item);
    if (ids.has(item.id))
      throw new Error(`Mergora FileUpload item id ${JSON.stringify(item.id)} is duplicated.`);
    ids.add(item.id);
  }
}

export function getFileUploadFingerprint(file: File): string {
  return `${file.name.normalize("NFC")}\u0000${file.size}\u0000${file.type}\u0000${file.lastModified}`;
}

function rejectedFromFile(
  file: File,
  reason: FileUploadRejectionReason,
  duplicateOf?: string,
): FileUploadRejectedFile {
  return Object.freeze({
    ...(duplicateOf === undefined ? {} : { duplicateOf }),
    name: file.name,
    reason,
    size: file.size,
    type: file.type,
  });
}

export const FileUpload = forwardRef<HTMLDivElement, FileUploadProps>(function FileUpload(
  {
    acceptedFileTypes,
    allowsMultiple = true,
    className,
    defaultItems = [],
    description,
    disabled = false,
    duplicatePolicy = "allow",
    form,
    getDuplicateKey = getFileUploadFingerprint,
    getFileId,
    id,
    items,
    label,
    maxFiles = 20,
    maxSizeBytes = 100 * 1024 * 1024,
    messages: messageOverrides,
    name,
    onCancel,
    onItemsChange,
    onRetry,
    onReset,
    onSelection,
    readOnly = false,
    required = false,
    renderPreview,
    reorderable = false,
    showCancelActions = false,
    showProgress = false,
    showRejectionRecovery = false,
    showRemoveActions = false,
    showRetryActions = false,
    validateFileSize = false,
    ...nativeProps
  },
  ref,
) {
  if (!hasVisibleContent(label)) throw new Error("Mergora FileUpload requires a visible label.");
  if (items !== undefined && defaultItems.length > 0) {
    throw new Error("Mergora FileUpload cannot combine items with defaultItems.");
  }
  if (duplicatePolicy !== "allow" && duplicatePolicy !== "reject") {
    throw new TypeError("Mergora FileUpload duplicatePolicy must be allow or reject.");
  }
  const [internalItems, setInternalItems] = useState<readonly FileUploadItem[]>(() => {
    assertItems(defaultItems);
    return Object.freeze([...defaultItems]);
  });
  const [rejections, setRejections] = useState<readonly FileUploadRejectedFile[]>([]);
  const [formSyncError, setFormSyncError] = useState(false);
  const currentItems = items ?? internalItems;
  assertItems(currentItems);
  if (showProgress) {
    for (const item of currentItems) assertProgressItem(item);
  }
  const controlled = items !== undefined;
  const messages = { ...DEFAULT_MESSAGES, ...messageOverrides };
  assertMessage(messages.empty, "empty message");
  assertMessage(messages.queueLabel, "queue label");
  assertMessage(messages.rejectedHeading, "rejected heading");
  const generatedId = useId().replaceAll(":", "");
  const resolvedId = id ?? `mrg-file-upload-${generatedId}`;
  const queueId = `${resolvedId}-queue`;
  const rejectionId = showRejectionRecovery ? `${resolvedId}-rejections` : undefined;
  const formSyncErrorId = formSyncError ? `${resolvedId}-form-sync-error` : undefined;
  const { locale } = useMergoraContext();
  const rootRef = useRef<HTMLDivElement>(null);
  const sequenceRef = useRef(0);
  const participatesInForm = form !== undefined || name !== undefined || required;

  useEffect(() => {
    if (!participatesInForm) {
      setFormSyncError(false);
      return;
    }
    const input = rootRef.current?.querySelector<HTMLInputElement>('input[type="file"]');
    if (input === null || input === undefined) {
      setFormSyncError(true);
      return;
    }
    try {
      synchronizeFileInputFiles(
        input,
        currentItems.map((item) => item.file),
      );
      input.setCustomValidity("");
      setFormSyncError(false);
    } catch {
      input.setCustomValidity("Selected files could not be added to the form. Choose them again.");
      setFormSyncError(true);
    }
  }, [currentItems, participatesInForm]);

  const commit = (next: readonly FileUploadItem[], detail: FileUploadChangeDetail): void => {
    const frozen = Object.freeze([...next]);
    if (!controlled) setInternalItems(frozen);
    onItemsChange?.(frozen, Object.freeze(detail));
  };

  const handleFiles = (result: FileSelectionResult): void => {
    const accepted: FileUploadItem[] = [];
    const rejected: FileUploadRejectedFile[] = result.rejected.map((entry) =>
      Object.freeze({ ...entry }),
    );
    const duplicateOwners = new Map<string, string>();
    if (duplicatePolicy === "reject") {
      for (const item of currentItems) duplicateOwners.set(getDuplicateKey(item.file), item.id);
    }
    const itemIds = new Set(currentItems.map((item) => item.id));
    for (const file of result.accepted) {
      if (currentItems.length + accepted.length >= maxFiles) {
        rejected.push(rejectedFromFile(file, "file-count"));
        continue;
      }
      if (duplicatePolicy === "reject") {
        const key = getDuplicateKey(file);
        const owner = duplicateOwners.get(key);
        if (owner !== undefined) {
          rejected.push(rejectedFromFile(file, "duplicate", owner));
          continue;
        }
      }
      let sequence = ++sequenceRef.current;
      let itemId =
        getFileId?.(file, sequence) ?? `${getFileUploadFingerprint(file)}\u0000${sequence}`;
      while (getFileId === undefined && itemIds.has(itemId)) {
        sequence = ++sequenceRef.current;
        itemId = `${getFileUploadFingerprint(file)}\u0000${sequence}`;
      }
      if (itemIds.has(itemId)) {
        throw new Error(
          `Mergora FileUpload generated duplicate item id ${JSON.stringify(itemId)}.`,
        );
      }
      const item = Object.freeze({ file, id: itemId, status: "queued" as const });
      assertItem(item);
      accepted.push(item);
      itemIds.add(item.id);
      if (duplicatePolicy === "reject") duplicateOwners.set(getDuplicateKey(file), item.id);
    }
    const selection = Object.freeze({
      accepted: Object.freeze(accepted),
      rejected: Object.freeze(rejected),
      source: result.source,
    });
    const next = [...currentItems, ...accepted];
    commit(next, { reason: "selection", selection });
    if (showRejectionRecovery) setRejections(selection.rejected);
    onSelection?.(selection);
  };

  const remove = (item: FileUploadItem): void => {
    commit(
      currentItems.filter((candidate) => candidate.id !== item.id),
      { itemId: item.id, reason: "remove" },
    );
  };

  const move = (index: number, offset: -1 | 1): void => {
    const destination = index + offset;
    if (destination < 0 || destination >= currentItems.length) return;
    const next = [...currentItems];
    const [item] = next.splice(index, 1);
    if (item === undefined) return;
    next.splice(destination, 0, item);
    commit(next, { itemId: item.id, reason: "reorder" });
  };

  const handleReset = (): void => {
    commit([], { reason: "reset" });
    if (showRejectionRecovery) setRejections([]);
    setFormSyncError(false);
    onReset?.();
  };

  return (
    <div
      {...nativeProps}
      aria-disabled={disabled || undefined}
      aria-describedby={[rejectionId, formSyncErrorId].filter(Boolean).join(" ") || undefined}
      className={className === undefined ? "mrg-file-upload" : `mrg-file-upload ${className}`}
      data-disabled={disabled ? "true" : undefined}
      data-readonly={readOnly ? "true" : undefined}
      data-slot="file-upload"
      id={resolvedId}
      ref={(node) => {
        rootRef.current = node;
        if (typeof ref === "function") ref(node);
        else if (ref !== null) ref.current = node;
      }}
    >
      <Dropzone
        {...(acceptedFileTypes === undefined ? {} : { acceptedFileTypes })}
        allowsMultiple={allowsMultiple}
        description={description}
        disabled={disabled || readOnly}
        label={label}
        maxFiles={maxFiles}
        maxSizeBytes={maxSizeBytes}
        onFiles={handleFiles}
        onReset={handleReset}
        required={required}
        validateFileSize={validateFileSize}
        {...(form === undefined ? {} : { form })}
        {...(name === undefined ? {} : { name })}
      />
      {formSyncError ? (
        <p data-slot="file-upload-form-error" id={formSyncErrorId} role="alert">
          Selected files could not be added to the form. Choose them again.
        </p>
      ) : null}
      <section aria-labelledby={`${queueId}-heading`} data-slot="file-upload-queue">
        <h2 data-slot="file-upload-queue-heading" id={`${queueId}-heading`}>
          {messages.queueLabel}
        </h2>
        {currentItems.length === 0 ? (
          <p data-slot="file-upload-empty">{messages.empty}</p>
        ) : (
          <ol data-slot="file-upload-items" id={queueId}>
            {currentItems.map((item, index) => {
              const status = item.status ?? "queued";
              return (
                <li data-slot="file-upload-item" data-status={status} key={item.id}>
                  {renderPreview === undefined ? null : (
                    <div data-slot="file-upload-preview">{renderPreview(item)}</div>
                  )}
                  <div data-slot="file-upload-file">
                    <strong>{item.file.name}</strong>
                    <span>
                      {formatUploadBytes(item.file.size, locale)}
                      {item.file.type.length === 0 ? "" : ` · ${item.file.type}`}
                    </span>
                  </div>
                  {showProgress ? (
                    <UploadProgress
                      announceProgress
                      label={item.file.name}
                      message={item.message}
                      status={status}
                      {...(item.totalBytes === undefined || item.uploadedBytes === undefined
                        ? {}
                        : { totalBytes: item.totalBytes, uploadedBytes: item.uploadedBytes })}
                      {...(item.progress === undefined ? {} : { value: item.progress })}
                    />
                  ) : null}
                  {reorderable || showCancelActions || showRemoveActions || showRetryActions ? (
                    <div data-slot="file-upload-actions">
                      {reorderable ? (
                        <>
                          <button
                            aria-label={assertMessage(
                              messages.moveUp(item.file.name),
                              "move-up label",
                            )}
                            disabled={disabled || readOnly || index === 0}
                            onClick={() => move(index, -1)}
                            type="button"
                          >
                            Earlier
                          </button>
                          <button
                            aria-label={assertMessage(
                              messages.moveDown(item.file.name),
                              "move-down label",
                            )}
                            disabled={disabled || readOnly || index === currentItems.length - 1}
                            onClick={() => move(index, 1)}
                            type="button"
                          >
                            Later
                          </button>
                        </>
                      ) : null}
                      {showRetryActions && status === "error" && onRetry !== undefined ? (
                        <button
                          disabled={disabled || readOnly}
                          onClick={() => onRetry(item)}
                          type="button"
                        >
                          {assertMessage(messages.retry(item.file.name), "retry label")}
                        </button>
                      ) : null}
                      {showCancelActions &&
                      ["queued", "retrying", "uploading"].includes(status) &&
                      onCancel !== undefined ? (
                        <button
                          disabled={disabled || readOnly}
                          onClick={() => onCancel(item)}
                          type="button"
                        >
                          {assertMessage(messages.cancel(item.file.name), "cancel label")}
                        </button>
                      ) : null}
                      {showRemoveActions ? (
                        <button
                          disabled={disabled || readOnly}
                          onClick={() => remove(item)}
                          type="button"
                        >
                          {assertMessage(messages.remove(item.file.name), "remove label")}
                        </button>
                      ) : null}
                    </div>
                  ) : null}
                </li>
              );
            })}
          </ol>
        )}
      </section>
      {showRejectionRecovery ? (
        <section aria-live="polite" data-slot="file-upload-rejections" id={rejectionId}>
          <h3>{messages.rejectedHeading}</h3>
          {rejections.length === 0 ? (
            <p>No files need attention.</p>
          ) : (
            <ul>
              {rejections.map((rejection, index) => (
                <li key={`${rejection.name}-${rejection.reason}-${index}`}>
                  <strong>{rejection.name}</strong>: {rejection.reason}
                </li>
              ))}
            </ul>
          )}
        </section>
      ) : null}
    </div>
  );
});

FileUpload.displayName = "FileUpload";

export { FileUpload, getFileUploadFingerprint } from "./file-upload";
export type {
  FileUploadChangeDetail,
  FileUploadChangeReason,
  FileUploadDuplicatePolicy,
  FileUploadItem,
  FileUploadMessages,
  FileUploadProps,
  FileUploadRejectedFile,
  FileUploadRejectionReason,
  FileUploadSelectionResult,
} from "./file-upload";

@layer mergora.components {
  .mrg-filter-builder {
    container-type: inline-size;
    display: grid;
    gap: var(--mrg-semantic-space-stack-md);
    color: var(--mrg-semantic-color-foreground-primary);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-filter-builder__heading,
  .mrg-filter-builder__drawer-heading {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-filter-builder__heading > strong,
  .mrg-filter-builder__drawer-heading > strong {
    font-size: var(--mrg-semantic-font-size-heading-small);
    font-weight: var(--mrg-semantic-font-weight-heading);
  }

  .mrg-filter-builder__editor {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
  }

  .mrg-filter-builder__filter {
    display: grid;
    grid-template-columns: repeat(3, minmax(8rem, 1fr)) auto;
    gap: var(--mrg-semantic-space-inline-sm);
    align-items: end;
    min-inline-size: 0;
    margin: 0;
    padding: var(--mrg-semantic-space-inset-md);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    background: var(--mrg-semantic-color-background-canvas);
  }

  .mrg-filter-builder__filter[data-invalid] {
    border-color: var(--mrg-semantic-color-status-danger-border);
  }

  .mrg-filter-builder__filter legend {
    padding-inline: var(--mrg-semantic-space-inline-xs);
    color: var(--mrg-semantic-color-brand-violet);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-filter-builder__filter label,
  .mrg-filter-builder__saved {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    min-inline-size: 0;
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-filter-builder__saved {
    max-inline-size: 24rem;
  }

  .mrg-filter-builder :is(button, input, select) {
    min-block-size: var(--mrg-semantic-size-target-minimum);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
  }

  .mrg-filter-builder :is(input, select) {
    inline-size: 100%;
    padding-inline: var(--mrg-semantic-density-control-padding-inline);
  }

  .mrg-filter-builder button {
    padding-inline: var(--mrg-semantic-density-control-padding-inline);
    cursor: pointer;
  }

  .mrg-filter-builder button:disabled,
  .mrg-filter-builder :is(input, select):disabled {
    border-color: var(--mrg-semantic-color-border-disabled);
    color: var(--mrg-semantic-color-foreground-disabled);
    background: var(--mrg-semantic-color-background-disabled);
    cursor: not-allowed;
  }

  .mrg-filter-builder :is(button, input, select):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  .mrg-filter-builder__actions {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-filter-builder__filter-error {
    grid-column: 1 / -1;
    margin: 0;
    color: var(--mrg-semantic-color-status-danger-foreground);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-filter-builder__empty {
    margin: 0;
    padding: var(--mrg-semantic-space-inset-md);
    border-block: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    color: var(--mrg-semantic-color-foreground-muted);
  }

  .mrg-filter-builder__summary {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-status-success-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-status-success-foreground);
    background: var(--mrg-semantic-color-status-success-background);
  }

  .mrg-filter-builder__summary ul {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-xs);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .mrg-filter-builder__summary li {
    padding: var(--mrg-semantic-space-inset-xs) var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid currentColor;
    border-radius: var(--mrg-semantic-radius-compact);
  }

  .mrg-filter-builder__drawer-trigger,
  .mrg-filter-builder__drawer {
    display: none;
  }

  .mrg-filter-builder__drawer {
    box-sizing: border-box;
    inline-size: min(100%, 32rem);
    max-inline-size: 100%;
    max-block-size: min(90dvb, 48rem);
    margin-block: auto 0;
    padding: var(--mrg-semantic-space-inset-md);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel) var(--mrg-semantic-radius-panel) 0 0;
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    overflow: auto;
  }

  .mrg-filter-builder__drawer::backdrop {
    background: var(--mrg-semantic-color-overlay-scrim);
  }

  @container (max-width: 34rem) {
    .mrg-filter-builder:has(.mrg-filter-builder__drawer) .mrg-filter-builder__inline {
      display: none;
    }

    .mrg-filter-builder__drawer-trigger,
    .mrg-filter-builder__drawer[open] {
      display: grid;
    }

    .mrg-filter-builder__filter {
      grid-template-columns: 1fr;
    }
  }

  @media (max-width: 34rem) {
    .mrg-filter-builder__filter {
      grid-template-columns: 1fr;
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-filter-builder *,
    .mrg-filter-builder *::before,
    .mrg-filter-builder *::after {
      scroll-behavior: auto !important;
      transition-duration: 0s !important;
    }
  }

  @media (forced-colors: active) {
    .mrg-filter-builder__filter,
    .mrg-filter-builder :is(button, input, select),
    .mrg-filter-builder__summary,
    .mrg-filter-builder__drawer {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }

    .mrg-filter-builder__filter[data-invalid] {
      border-color: Mark;
    }

    .mrg-filter-builder :is(button, input, select):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }

    .mrg-filter-builder__drawer::backdrop {
      background: Canvas;
    }
  }
}

"use client";

import "./filter-builder.css";

import {
  useEffect,
  useId,
  useRef,
  useState,
  type FormEvent,
  type HTMLAttributes,
  type ReactElement,
  type ReactNode,
} from "react";

export interface FilterBuilderOperator {
  /** Provides the stable operator value stored in each filter. */
  readonly id: string;
  /** Presents the operator name in the editor and active summary. */
  readonly label: string;
  /** Removes the value editor when false, for operators such as “is empty”. */
  readonly requiresValue?: boolean;
}

export interface FilterBuilderField {
  /** Provides the stable field value stored in each filter. */
  readonly id: string;
  /** Presents the field name in selectors and active summaries. */
  readonly label: string;
  /** Restricts the operator selector to choices valid for this field. */
  readonly operators: readonly FilterBuilderOperator[];
}

export interface FilterBuilderFilter {
  /** Identifies this filter for controlled updates, removal, and stable rendering. */
  readonly id: string;
  /** References a field identifier supplied through the fields collection. */
  readonly field: string;
  /** References an operator valid for the selected field. */
  readonly operator: string;
  /** Stores the canonical consumer value without imposing domain-specific parsing. */
  readonly value: string;
}

export interface FilterBuilderSavedFilter {
  /** Provides a stable identifier for the saved-filter choice. */
  readonly id: string;
  /** Presents a domain-neutral name for the saved-filter choice. */
  readonly label: string;
  /** Supplies the complete filter set applied when this saved choice is selected. */
  readonly filters: readonly FilterBuilderFilter[];
}

export interface FilterBuilderUrlAdapter {
  /** Optionally reads a serialized initial value from consumer-controlled URL state. */
  readonly read?: () => string;
  /** Receives serialized changes and their reason without choosing a routing library. */
  readonly write: (
    serialized: string,
    detail: { readonly reason: FilterBuilderChangeReason },
  ) => void;
}

export type FilterBuilderChangeReason = "add" | "remove" | "update" | "clear" | "saved" | "reset";

export interface FilterBuilderMessages {
  /** Labels the action that appends a new editable filter. */
  readonly add: string;
  /** Labels the action that removes one editable filter. */
  readonly remove: string;
  /** Labels the action that removes every active filter. */
  readonly clear: string;
  /** Labels each filter’s field selector. */
  readonly field: string;
  /** Labels each filter’s operator selector. */
  readonly operator: string;
  /** Labels each filter’s canonical value input. */
  readonly value: string;
  /** Names the optional summary of currently active filters. */
  readonly activeSummary: string;
  /** Names the optional saved-filter selector. */
  readonly savedFilters: string;
  /** Labels the action that applies a saved filter set. */
  readonly applySaved: string;
  /** Labels the narrow-screen action that opens the filter editor. */
  readonly mobileOpen: string;
  /** Labels the narrow-screen action that closes the filter editor. */
  readonly mobileClose: string;
  /** Describes the state in which no filters are active. */
  readonly empty: string;
  /** Generates the accessible name for a filter at the given one-based position. */
  readonly filterLabel: (position: number) => string;
  /** Generates the accessible drawer name from the root label. */
  readonly drawerLabel: (label: string) => string;
  /** Generates the narrow-screen action label with the active filter count. */
  readonly editCount: (label: string, count: number) => string;
  /** Explains how to recover when a required filter value is missing. */
  readonly valueRecovery: string;
  /** Replaces an absent value in the optional active-filter summary. */
  readonly missingSummaryValue: string;
}

export interface FilterBuilderProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children" | "onChange"
> {
  /** Names the filter builder for visible and assistive-technology context. */
  readonly label: string;
  /** Defines selectable fields and the operators valid for each field. */
  readonly fields: readonly FilterBuilderField[];
  /** Controls the complete filter collection when supplied. */
  readonly filters?: readonly FilterBuilderFilter[];
  /** Sets the initial filter collection for uncontrolled use. */
  readonly defaultFilters?: readonly FilterBuilderFilter[];
  /** Reports filter changes with the operation and affected identifier. */
  readonly onFiltersChange?: (
    filters: readonly FilterBuilderFilter[],
    detail: { readonly reason: FilterBuilderChangeReason; readonly filterId?: string },
  ) => void;
  /** Serializes active filters into a hidden successful control for native form submission. */
  readonly name?: string;
  /** Prevents editing, saved-filter application, clearing, and URL writes. */
  readonly disabled?: boolean;
  /** Preserves values and form submission while removing mutating controls. */
  readonly readOnly?: boolean;
  /** Shows a compact active-filter summary; false removes its UI and semantics. */
  readonly showActiveSummary?: boolean;
  /** Customizes each optional summary entry without changing canonical filter values. */
  readonly renderFilterSummary?: (filter: FilterBuilderFilter) => ReactNode;
  /** Enables saved choices with an array; false removes their UI and behavior. */
  readonly savedFilters?: false | readonly FilterBuilderSavedFilter[];
  /** Enables consumer-owned URL synchronization; false removes all adapter reads and writes. */
  readonly urlAdapter?: false | FilterBuilderUrlAdapter;
  /** Moves editing into a narrow-screen drawer; false keeps the editor inline. */
  readonly mobileDrawer?: boolean;
  /** Overrides individual localized strings while retaining defaults for omitted entries. */
  readonly messages?: Partial<FilterBuilderMessages>;
}

const defaultMessages: FilterBuilderMessages = {
  add: "Add filter",
  remove: "Remove",
  clear: "Clear filters",
  field: "Field",
  operator: "Operator",
  value: "Value",
  activeSummary: "Active filters",
  savedFilters: "Saved filters",
  applySaved: "Apply saved filter",
  mobileOpen: "Edit filters",
  mobileClose: "Done",
  empty: "No filters applied.",
  filterLabel: (position) => `Filter ${position}`,
  drawerLabel: (label) => `${label}: filter editor`,
  editCount: (label, count) => `${label} (${count})`,
  valueRecovery: "Enter a value for this filter or choose an operator that does not need one.",
  missingSummaryValue: "value needed",
};

const separator = "\u001f";

function classes(...values: readonly (string | false | undefined)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}

export function serializeFilters(filters: readonly FilterBuilderFilter[]): string {
  const parameters = new URLSearchParams();
  for (const filter of filters) {
    parameters.append(
      "filter",
      [filter.id, filter.field, filter.operator, filter.value].join(separator),
    );
  }
  return parameters.toString();
}

export function parseFilters(serialized: string): readonly FilterBuilderFilter[] {
  const parameters = new URLSearchParams(
    serialized.startsWith("?") ? serialized.slice(1) : serialized,
  );
  const seen = new Set<string>();
  return parameters.getAll("filter").map((entry) => {
    const [id, field, operator, value, ...extra] = entry.split(separator);
    if (
      extra.length > 0 ||
      !id ||
      !field ||
      !operator ||
      seen.has(id) ||
      id.length > 120 ||
      field.length > 120 ||
      operator.length > 120 ||
      (value?.length ?? 0) > 2000
    ) {
      throw new Error("Mergora FilterBuilder received an invalid serialized filter.");
    }
    seen.add(id);
    return { id, field, operator, value: value ?? "" };
  });
}

export function FilterBuilder({
  label,
  fields,
  filters: controlledFilters,
  defaultFilters: defaultFiltersProp,
  onFiltersChange,
  name,
  disabled = false,
  readOnly = false,
  showActiveSummary = false,
  renderFilterSummary,
  savedFilters = false,
  urlAdapter = false,
  mobileDrawer = false,
  messages: messageOverrides,
  className,
  onReset,
  ...props
}: FilterBuilderProps): ReactElement {
  const defaultFilters = defaultFiltersProp ?? [];
  if (
    fields.length === 0 ||
    fields.some(
      (field) =>
        field.id.length === 0 ||
        field.operators.length === 0 ||
        field.operators.some((operator) => operator.id.length === 0) ||
        new Set(field.operators.map((operator) => operator.id)).size !== field.operators.length,
    ) ||
    new Set(fields.map((field) => field.id)).size !== fields.length
  ) {
    throw new Error("Mergora FilterBuilder requires unique fields with unique operators.");
  }
  if (controlledFilters !== undefined && defaultFiltersProp !== undefined) {
    throw new Error(
      "Mergora FilterBuilder controlled filters cannot be combined with defaultFilters.",
    );
  }
  const messages = { ...defaultMessages, ...messageOverrides };
  const reactId = useId().replaceAll(":", "");
  const nextId = useRef(0);
  const drawer = useRef<HTMLDialogElement>(null);
  const drawerTrigger = useRef<HTMLButtonElement>(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [internalFilters, setInternalFilters] = useState<readonly FilterBuilderFilter[]>(() => {
    if (controlledFilters !== undefined || urlAdapter === false || urlAdapter.read === undefined) {
      return defaultFilters;
    }
    const serialized = urlAdapter.read();
    return serialized === "" ? defaultFilters : parseFilters(serialized);
  });
  const filters = controlledFilters ?? internalFilters;
  if (
    filters.some(
      (filter) =>
        filter.id.length === 0 ||
        filter.id.length > 120 ||
        filter.field.length === 0 ||
        filter.field.length > 120 ||
        filter.operator.length === 0 ||
        filter.operator.length > 120 ||
        filter.value.length > 2000,
    ) ||
    new Set(filters.map((filter) => filter.id)).size !== filters.length
  ) {
    throw new Error("Mergora FilterBuilder filters require valid, unique IDs and bounded values.");
  }
  const firstField = fields[0]!;

  useEffect(() => {
    if (!mobileDrawer) return;
    const element = drawer.current;
    if (element === null) return;
    if (drawerOpen && !element.open) element.showModal();
    if (!drawerOpen && element.open) element.close();
  }, [drawerOpen, mobileDrawer]);

  const commit = (
    next: readonly FilterBuilderFilter[],
    reason: FilterBuilderChangeReason,
    filterId?: string,
  ) => {
    if (controlledFilters === undefined) setInternalFilters(next);
    onFiltersChange?.(next, { reason, ...(filterId ? { filterId } : {}) });
    if (urlAdapter !== false) urlAdapter.write(serializeFilters(next), { reason });
  };
  const add = () => {
    const id = `${reactId}-filter-${String(++nextId.current)}`;
    commit(
      [
        ...filters,
        {
          id,
          field: firstField.id,
          operator: firstField.operators[0]!.id,
          value: "",
        },
      ],
      "add",
      id,
    );
  };
  const update = (id: string, patch: Partial<FilterBuilderFilter>) =>
    commit(
      filters.map((filter) => (filter.id === id ? { ...filter, ...patch } : filter)),
      "update",
      id,
    );
  const remove = (id: string) =>
    commit(
      filters.filter((filter) => filter.id !== id),
      "remove",
      id,
    );
  const summaryFor = (filter: FilterBuilderFilter): ReactNode => {
    if (renderFilterSummary) return renderFilterSummary(filter);
    const field = fields.find((item) => item.id === filter.field);
    const operator = field?.operators.find((item) => item.id === filter.operator);
    return `${field?.label ?? filter.field} ${operator?.label ?? filter.operator}${operator?.requiresValue === false ? "" : ` ${filter.value || messages.missingSummaryValue}`}`;
  };

  const editor = (surface: "inline" | "drawer") => (
    <div
      className="mrg-filter-builder__editor"
      data-surface={surface}
      data-slot={`filter-builder-${surface}-editor`}
    >
      {filters.length === 0 ? <p className="mrg-filter-builder__empty">{messages.empty}</p> : null}
      {filters.map((filter, index) => {
        const field = fields.find((item) => item.id === filter.field) ?? firstField;
        const operator = field.operators.find((item) => item.id === filter.operator);
        const invalid = operator?.requiresValue !== false && filter.value.trim() === "";
        const errorId = `${reactId}-${surface}-${encodeURIComponent(filter.id)}-error`;
        return (
          <fieldset
            key={filter.id}
            className="mrg-filter-builder__filter"
            data-invalid={invalid || undefined}
          >
            <legend>{messages.filterLabel(index + 1)}</legend>
            <label>
              <span>{messages.field}</span>
              <select
                value={filter.field}
                disabled={disabled || readOnly}
                onChange={(event) => {
                  const nextField = fields.find((item) => item.id === event.currentTarget.value)!;
                  update(filter.id, {
                    field: nextField.id,
                    operator: nextField.operators[0]!.id,
                    value: "",
                  });
                }}
              >
                {fields.map((item) => (
                  <option key={item.id} value={item.id}>
                    {item.label}
                  </option>
                ))}
              </select>
            </label>
            <label>
              <span>{messages.operator}</span>
              <select
                value={filter.operator}
                disabled={disabled || readOnly}
                onChange={(event) => update(filter.id, { operator: event.currentTarget.value })}
              >
                {field.operators.map((item) => (
                  <option key={item.id} value={item.id}>
                    {item.label}
                  </option>
                ))}
              </select>
            </label>
            {operator?.requiresValue === false ? null : (
              <label>
                <span>{messages.value}</span>
                <input
                  value={filter.value}
                  disabled={disabled}
                  readOnly={readOnly}
                  aria-invalid={invalid || undefined}
                  aria-describedby={invalid ? errorId : undefined}
                  onChange={(event) => update(filter.id, { value: event.currentTarget.value })}
                />
              </label>
            )}
            {!readOnly ? (
              <button type="button" disabled={disabled} onClick={() => remove(filter.id)}>
                {messages.remove}
              </button>
            ) : null}
            {invalid ? (
              <p id={errorId} className="mrg-filter-builder__filter-error">
                {messages.valueRecovery}
              </p>
            ) : null}
          </fieldset>
        );
      })}
      {!readOnly ? (
        <div className="mrg-filter-builder__actions">
          <button type="button" disabled={disabled} onClick={add}>
            {messages.add}
          </button>
          <button
            type="button"
            disabled={disabled || filters.length === 0}
            onClick={() => commit([], "clear")}
          >
            {messages.clear}
          </button>
        </div>
      ) : null}
    </div>
  );

  const handleReset = (event: FormEvent<HTMLDivElement>) => {
    onReset?.(event);
    if (!event.defaultPrevented && controlledFilters === undefined) {
      setInternalFilters(defaultFilters);
      onFiltersChange?.(defaultFilters, { reason: "reset" });
      if (urlAdapter !== false)
        urlAdapter.write(serializeFilters(defaultFilters), { reason: "reset" });
    }
  };

  return (
    <div
      {...props}
      className={classes("mrg-filter-builder", className)}
      data-slot="filter-builder"
      role="region"
      aria-label={label}
      aria-disabled={disabled || undefined}
      onReset={handleReset}
    >
      <div className="mrg-filter-builder__heading">
        <strong>{label}</strong>
        {mobileDrawer ? (
          <button
            ref={drawerTrigger}
            type="button"
            className="mrg-filter-builder__drawer-trigger"
            onClick={() => setDrawerOpen(true)}
          >
            {messages.editCount(messages.mobileOpen, filters.length)}
          </button>
        ) : null}
      </div>
      {savedFilters !== false ? (
        <label className="mrg-filter-builder__saved">
          <span>{messages.savedFilters}</span>
          <select
            defaultValue=""
            disabled={disabled || readOnly || savedFilters.length === 0}
            onChange={(event) => {
              const saved = savedFilters.find((item) => item.id === event.currentTarget.value);
              if (saved) commit(saved.filters, "saved");
              event.currentTarget.value = "";
            }}
          >
            <option value="">{messages.applySaved}</option>
            {savedFilters.map((saved) => (
              <option key={saved.id} value={saved.id}>
                {saved.label}
              </option>
            ))}
          </select>
        </label>
      ) : null}
      <div className="mrg-filter-builder__inline">{editor("inline")}</div>
      {mobileDrawer ? (
        <dialog
          ref={drawer}
          className="mrg-filter-builder__drawer"
          aria-label={messages.drawerLabel(label)}
          onCancel={() => setDrawerOpen(false)}
          onClose={() => {
            setDrawerOpen(false);
            drawerTrigger.current?.focus();
          }}
        >
          <div className="mrg-filter-builder__drawer-heading">
            <strong>{label}</strong>
            <button type="button" onClick={() => setDrawerOpen(false)}>
              {messages.mobileClose}
            </button>
          </div>
          {editor("drawer")}
        </dialog>
      ) : null}
      {name ? (
        <input type="hidden" name={name} value={serializeFilters(filters)} disabled={disabled} />
      ) : null}
      {showActiveSummary ? (
        <output
          className="mrg-filter-builder__summary"
          data-slot="filter-builder-summary"
          aria-live="polite"
        >
          <strong>{messages.activeSummary}</strong>
          {filters.length === 0 ? (
            <span>{messages.empty}</span>
          ) : (
            <ul>
              {filters.map((filter) => (
                <li key={filter.id}>{summaryFor(filter)}</li>
              ))}
            </ul>
          )}
        </output>
      ) : null}
    </div>
  );
}

export { FilterBuilder, parseFilters, serializeFilters } from "./filter-builder";
export type {
  FilterBuilderChangeReason,
  FilterBuilderField,
  FilterBuilderFilter,
  FilterBuilderMessages,
  FilterBuilderOperator,
  FilterBuilderProps,
  FilterBuilderSavedFilter,
  FilterBuilderUrlAdapter,
} from "./filter-builder";

