  .mrg-number-field-stepper,
  .mrg-number-field-scrub {
    align-items: center;
    appearance: none;
    background: var(--mrg-semantic-color-background-surface);
    border: 0;
    color: inherit;
    display: inline-flex;
    flex: 0 0 auto;
    font: inherit;
    inline-size: var(--mrg-semantic-size-target-minimum);
    justify-content: center;
    min-block-size: var(--mrg-semantic-size-target-minimum);
    padding: 0;
  }

  .mrg-number-field-stepper[data-slot="number-field-decrement"],
  .mrg-number-field-scrub {
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
  }

  .mrg-number-field-stepper[data-slot="number-field-increment"] {
    border-inline-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
  }

  .mrg-number-field-stepper:not([data-disabled]):hover,
  .mrg-number-field-scrub:not(:disabled):hover {
    background: var(--mrg-semantic-color-background-surface-sunken);
  }

  .mrg-number-field-stepper[data-pressed],
  .mrg-number-field-scrub:active {
    background: var(--mrg-semantic-color-action-background);
    color: var(--mrg-semantic-color-action-foreground);
  }

  .mrg-number-field-stepper[data-focus-visible],
  .mrg-number-field-scrub:focus-visible {
    box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
      var(--mrg-component-focus-indicator-contrast-background);
    outline: var(--mrg-component-focus-indicator-width) solid
      var(--mrg-component-focus-indicator-color);
    outline-offset: calc(var(--mrg-component-focus-indicator-width) * -1);
    position: relative;
