    unicode-bidi: plaintext;
  }

  .mrg-number-field[data-readonly] .mrg-number-field-stepper,
  .mrg-number-field[data-readonly] .mrg-number-field-scrub {
    display: none;
  }

  @media (pointer: coarse) {
    .mrg-number-field-group,
    .mrg-number-field-input,
    .mrg-number-field-stepper,
    .mrg-number-field-scrub {
