  @media (forced-colors: active) {
    .mrg-onboarding-wizard,
    .mrg-onboarding-wizard [data-slot="onboarding-header"],
    .mrg-onboarding-wizard > [data-slot="stepper"],
    .mrg-onboarding-wizard
