    var(--mrg-semantic-color-border-subtle);
  inline-size: 1em;
}

.mrg-otp-field [data-slot="otp-field-grouping-label"] {
  block-size: 1px;
  clip-path: inset(50%);
  inline-size: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
}

@media (pointer: coarse) {
  .mrg-otp-field [data-slot="otp-field-control"],
  .mrg-otp-field-input {
    min-block-size: var(--mrg-semantic-size-target-preferred);
