.mrg-popover {
  box-sizing: border-box;
  max-block-size: min(var(--available-height, 80dvb), calc(100dvb - 1rem));
  max-inline-size: min(
    var(--mrg-semantic-size-content-prose),
    calc(100dvi - var(--mrg-semantic-space-stack-md) - var(--mrg-semantic-space-stack-md))
  );
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-overlay);
  background: var(--mrg-semantic-color-background-canvas);
  box-shadow: var(--mrg-semantic-elevation-overlay);
  color: var(--mrg-semantic-color-foreground-primary);
  overflow: visible;
  transform-origin: var(--trigger-anchor-point);
  z-index: calc(
    var(--mrg-component-layer-stack-base, var(--mrg-semantic-layer-modal)) +
