.mrg-popover__content {
  box-sizing: border-box;
  max-block-size: inherit;
  max-inline-size: inherit;
  overflow: auto;
  overscroll-behavior: contain;
  padding: var(--mrg-semantic-density-panel-padding);
  border-radius: inherit;
  outline: none;
  overflow-wrap: anywhere;
  scrollbar-gutter: stable;
}

.mrg-popover__title {
  margin: 0;
  font-size: var(--mrg-semantic-font-size-heading-small);
  font-weight: var(--mrg-semantic-font-weight-heading);
  line-height: var(--mrg-semantic-font-line-height-heading);
  text-wrap: balance;
}

.mrg-popover__description {
  max-inline-size: 65ch;
  margin-block: var(--mrg-semantic-space-stack-xs) var(--mrg-semantic-space-stack-md);
  color: var(
    --mrg-component-popover-description-foreground,
    var(--mrg-semantic-color-foreground-primary)
  );
  text-wrap: pretty;
}

.mrg-popover__anchor-context {
  margin-block-end: var(--mrg-semantic-space-stack-sm);
  padding-block-end: var(--mrg-semantic-space-inline-sm);
  border-block-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-default);
  color: var(--mrg-semantic-color-status-neutral-foreground);
  font-size: var(--mrg-semantic-font-size-label);
  font-weight: var(--mrg-semantic-font-weight-label);
  line-height: var(--mrg-semantic-font-line-height-body);
