  }

  .mrg-tree-grid__header {
    position: sticky;
    inset-block-start: 0;
    z-index: var(--mrg-semantic-layer-sticky);
    border-block-start: 0 !important;
    color: var(--mrg-semantic-color-foreground-muted);
    background: var(--mrg-semantic-color-background-surface);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-tree-grid [role="columnheader"],
  .mrg-tree-grid [role="gridcell"] {
    box-sizing: border-box;
    min-inline-size: 0;
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    border-inline-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    overflow-wrap: anywhere;
