  .mrg-tree-grid [role="columnheader"]:first-child,
  .mrg-tree-grid [role="gridcell"]:first-child {
    border-inline-start: 0;
  }

  .mrg-tree-grid [role="row"][data-selected] [role="gridcell"] {
    color: var(--mrg-semantic-color-selection-foreground);
