  .mrg-tree-grid [role="gridcell"]:focus-visible,
  .mrg-tree-grid :is(button, input):focus-visible {
    position: relative;
    z-index: 1;
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
